    /**
     * Execute an HTTP request and return the response.
     */
    private IoTResponse executeRequest(OkHttpClient client, Request request, String operationName) throws IoTHttpException {
        if (!isNetworkAvailable()) {
            throw new IoTHttpException("No network connection available for " + operationName);
        }

        try (Response response = client.newCall(request).execute()) {
            String responseBody = null;
            if (response.body() != null) {
                long contentLength = response.body().contentLength();
                if (contentLength > MAX_RESPONSE_SIZE) {
                    throw new IoTHttpException("Response too large: " + contentLength + " bytes (max: " + MAX_RESPONSE_SIZE + ")");
                }
                responseBody = readResponseBodySafely(response);
            }

            // Validate content type to prevent content sniffing attacks
            String contentType = response.header("Content-Type");
            if (contentType != null && !contentType.contains("application/json") && !contentType.contains("text/plain")) {
                Log.w(TAG, operationName + " received unexpected content type: " + contentType);
            }

            return new IoTResponse(
                    response.code(),
                    responseBody,
                    response.headers().toMultimap(),
                    response.isSuccessful()
            );
        } catch (IOException e) {
            throw new IoTHttpException(operationName + " failed: " + e.getMessage(), e);
        }
    }

    /**
     * Read response body with size limit enforcement.
     */
    private String readResponseBodySafely(Response response) throws IOException, IoTHttpException {
        if (response.body() == null) {
            return null;
        }

        try (InputStream is = response.body().byteStream();
             BufferedReader reader = new BufferedReader(new InputStreamReader(is, StandardCharsets.UTF_8))) {

            StringBuilder sb = new StringBuilder();
            char[] buffer = new char[4096];
            int totalRead = 0;
            int charsRead;

            while ((charsRead = reader.read(buffer)) != -1) {
                totalRead += charsRead;
                if (totalRead > MAX_RESPONSE_SIZE) {
                    throw new IoTHttpException("Response body exceeds maximum allowed size of " + MAX_RESPONSE_SIZE + " bytes");
                }
                sb.append(buffer, 0, charsRead);
            }

            return sb.toString();
        }
    }

    /**
     * Build a cloud API URL from a path.
     */
    private String buildCloudUrl(String path) throws IoTHttpException {
        if (path == null) {
            throw new IoTHttpException("Path cannot be null");
        }

        // Sanitize path to prevent path traversal
        String sanitizedPath = sanitizePath(path);
        String baseUrl = cloudApiBaseUrl.endsWith("/") ? cloudApiBaseUrl.substring(0, cloudApiBaseUrl.length() - 1) : cloudApiBaseUrl;
        String fullPath = sanitizedPath.startsWith("/") ? sanitizedPath : "/" + sanitizedPath;

        return baseUrl + fullPath;
    }

    /**
     * Build a local device URL.
     */
    private String buildLocalUrl(String scheme, String ip, int port, String path) throws IoTHttpException {
        if (port < 1 || port > 65535) {
            throw new IoTHttpException("Invalid port number: " + port);
        }

        String sanitizedPath = sanitizePath(path);
        String fullPath = sanitizedPath.startsWith("/") ? sanitizedPath : "/" + sanitizedPath;

        return scheme + "://" + ip + ":" + port + fullPath;
    }

    /**
     * Sanitize a URL path to prevent path traversal attacks.
     */
    private String sanitizePath(String path) throws IoTHttpException {
        if (path == null || path.isEmpty()) {
            return "/";
        }

        // Reject paths with path traversal sequences
        if (path.contains("..") || path.contains("//") || path.contains("\\")) {
            throw new IoTHttpException("Invalid path: contains forbidden sequences");
        }

        // Validate the path is a proper URI path
        try {
            URI uri = new URI(null, null, path, null);
            return uri.getPath();
        } catch (URISyntaxException e) {
            throw new IoTHttpException("Invalid path: " + e.getMessage());
        }
    }

